import { useState, useRef, useCallback, useEffect } from 'react';

interface UsePullToRefreshOptions {
  onRefresh: () => Promise<void>;
  threshold?: number;
  maxPull?: number;
}

export function usePullToRefresh({
  onRefresh,
  threshold = 80,
  maxPull = 120
}: UsePullToRefreshOptions) {
  const [pullDistance, setPullDistance] = useState(0);
  const [isRefreshing, setIsRefreshing] = useState(false);
  
  const startY = useRef(0);
  const pullDistanceRef = useRef(0);
  const isPullingRef = useRef(false);
  const isRefreshingRef = useRef(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const onRefreshRef = useRef(onRefresh);
  // Track if pull was activated (passed initial threshold)
  const pullActivatedRef = useRef(false);
  
  useEffect(() => {
    onRefreshRef.current = onRefresh;
  }, [onRefresh]);

  useEffect(() => {
    isRefreshingRef.current = isRefreshing;
  }, [isRefreshing]);

  // More robust top detection for WebViews
  // 更健壮的顶部检测，兼容各种 WebView 环境
  const isAtTop = useCallback(() => {
    try {
      const windowScroll = window.scrollY || window.pageYOffset || 0;
      const documentScroll = document.documentElement?.scrollTop || 0;
      const bodyScroll = document.body?.scrollTop || 0;
      const containerScroll = containerRef.current?.scrollTop || 0;
      
      const scrollTop = Math.max(windowScroll, documentScroll, bodyScroll, containerScroll);
      
      // Use a lenient threshold for WebView compatibility
      // WebView 中滚动位置可能有微小偏移，使用宽松阈值
      if (scrollTop <= 10) return true;

      // Fallback: getBoundingClientRect for WebView environments
      const container = containerRef.current;
      if (container) {
        const rect = container.getBoundingClientRect();
        // If container top is near viewport top (accounting for nav)
        if (rect.top >= -10) return true;
      }
      
      return false;
    } catch {
      return false;
    }
  }, []);

  // Don't check isAtTop at touchstart - check during touchmove instead
  // 在 touchstart 时不检查是否在顶部，而是在 touchmove 时检查
  // This prevents missing the event in WebViews where scroll position may be delayed
  const handleTouchStart = useCallback((e: TouchEvent) => {
    if (isRefreshingRef.current) return;
    
    startY.current = e.touches[0].clientY;
    isPullingRef.current = false;
    pullActivatedRef.current = false;
  }, []);

  const handleTouchMove = useCallback((e: TouchEvent) => {
    if (isRefreshingRef.current) return;
    
    const currentY = e.touches[0].clientY;
    const diff = currentY - startY.current;
    
    // Only pull down, not up
    if (diff <= 0) {
      if (pullActivatedRef.current) {
        pullActivatedRef.current = false;
        isPullingRef.current = false;
        pullDistanceRef.current = 0;
        setPullDistance(0);
      }
      return;
    }

    // Activate pull only when: pulling down AND at top of page
    // 仅当向下拉动且在页面顶部时激活下拉刷新
    if (!pullActivatedRef.current) {
      if (diff > 5 && isAtTop()) {
        pullActivatedRef.current = true;
        isPullingRef.current = true;
        // Reset startY to current position for accurate distance calculation
        startY.current = currentY;
      }
      return;
    }

    // Pull is activated - prevent native scroll and update distance
    // 下拉已激活，阻止原生滚动并更新拉动距离
    e.preventDefault();
    e.stopPropagation();
    
    const actualDiff = currentY - startY.current;
    const resistance = 0.6;
    const distance = Math.min(Math.max(actualDiff * resistance, 0), maxPull);
    pullDistanceRef.current = distance;
    setPullDistance(distance);
  }, [maxPull, isAtTop]);

  const handleTouchEnd = useCallback(async () => {
    if (!pullActivatedRef.current) return;
    
    pullActivatedRef.current = false;
    isPullingRef.current = false;
    const currentPullDistance = pullDistanceRef.current;
    
    if (currentPullDistance >= threshold && !isRefreshingRef.current) {
      setIsRefreshing(true);
      isRefreshingRef.current = true;
      setPullDistance(threshold);
      
      try {
        await onRefreshRef.current();
      } finally {
        setIsRefreshing(false);
        isRefreshingRef.current = false;
        pullDistanceRef.current = 0;
        setPullDistance(0);
      }
    } else {
      pullDistanceRef.current = 0;
      setPullDistance(0);
    }
  }, [threshold]);

  const handleTouchCancel = useCallback(() => {
    pullActivatedRef.current = false;
    isPullingRef.current = false;
    pullDistanceRef.current = 0;
    setPullDistance(0);
  }, []);

  // Bind to document for better WebView event capture
  // 绑定到 document 以更好地捕获 WebView 中的触摸事件
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    // Use document-level listeners for better WebView compatibility
    // WebView 中容器级监听可能被原生滚动拦截，使用 document 级别更可靠
    const touchMoveOptions = { passive: false } as AddEventListenerOptions;
    const passiveOptions = { passive: true } as AddEventListenerOptions;
    
    document.addEventListener('touchstart', handleTouchStart, passiveOptions);
    document.addEventListener('touchmove', handleTouchMove, touchMoveOptions);
    document.addEventListener('touchend', handleTouchEnd, passiveOptions);
    document.addEventListener('touchcancel', handleTouchCancel, passiveOptions);

    return () => {
      document.removeEventListener('touchstart', handleTouchStart);
      document.removeEventListener('touchmove', handleTouchMove);
      document.removeEventListener('touchend', handleTouchEnd);
      document.removeEventListener('touchcancel', handleTouchCancel);
    };
  }, [handleTouchStart, handleTouchMove, handleTouchEnd, handleTouchCancel]);

  const progress = Math.min(pullDistance / threshold, 1);

  return {
    containerRef,
    isPulling: isPullingRef.current,
    isRefreshing,
    pullDistance,
    progress
  };
}
